sql:
SELECT t.trade_id, c.commodity_name
FROM trade_data t
JOIN commodities c ON t.commodity_code = c.commodity_code;

SELECT year, SUM(value_usd) AS total_value
FROM trade_data
GROUP BY year;

SELECT AVG(value_usd) AS average_value
FROM trade_data
WHERE year = 2020;

SELECT trader_id, COUNT(*) as trade_count
FROM trader_trade_relation
GROUP BY trader_id;

external_knowledge:
- 'Golden geese' metaphorically refers to the most profitable or valuable traders;
- 'Spread their wings to the international market' is a metaphor for engaging in export activities;
- 'Bearing the most valuable eggs' symbolizes the export trades with the highest monetary value;
- 'Weight of these precious treasures' is a figurative expression for the US dollar value of the exports.

sql:
SELECT commodity_name, category
FROM commodities
ORDER BY commodity_name ASC;
